export function initialize(dotNetRef, element, timeoutMs) {
    let timer = null;
    let isIdle = false;

    const events = ["mousemove", "keydown", "click", "scroll", "touchstart"];

    function resetTimer() {
        if (isIdle) {
            isIdle = false;
            dotNetRef.invokeMethodAsync("OnUserActive");
        }
        clearTimeout(timer);
        timer = setTimeout(() => {
            isIdle = true;
            dotNetRef.invokeMethodAsync("OnUserIdle");
        }, timeoutMs);
    }

    for (const evt of events) {
        element.addEventListener(evt, resetTimer, { passive: true });
    }

    // Start the initial timer
    timer = setTimeout(() => {
        isIdle = true;
        dotNetRef.invokeMethodAsync("OnUserIdle");
    }, timeoutMs);

    return {
        dispose: () => {
            clearTimeout(timer);
            for (const evt of events) {
                element.removeEventListener(evt, resetTimer);
            }
        }
    };
}

