                "import", "./js/userActivityTracker.js");
            _tracker = await _module.InvokeAsync<IJSObjectReference>(
                "initialize", _dotNetRef, _element, TimeoutSeconds * 1000);
        }
    }

    [JSInvokable]
    public async Task OnUserIdle() => await OnIdle.InvokeAsync();

    [JSInvokable]
    public async Task OnUserActive() => await OnActive.InvokeAsync();

    public async ValueTask DisposeAsync()
    {
        if (_tracker is not null)
        {
            await _tracker.InvokeVoidAsync("dispose");
            await _tracker.DisposeAsync();
        }
        if (_module is not null)
        {
            await _module.DisposeAsync();
        }
        _dotNetRef?.Dispose();
    }
}

